 16â†’// â”€â”€ Bundled font setup for Sharp/librsvg SVG text rendering â”€â”€
 17â†’const __filename = fileURLToPath(import.meta.url);
 18â†’const __dirname = dirname(__filename);
 19â†’const FONT_DIR = join(__dirname, '.fonts');
 20â†’const FONT_PATH = join(FONT_DIR, 'DejaVuSans.ttf');
 21â†’const FONT_BOLD_PATH = join(FONT_DIR, 'DejaVuSans-Bold.ttf');
 22â†’let fontsReady = false;
 23â†’
 24â†’async function ensureShareFonts() {
 25â†’    if (fontsReady) return;
 26â†’    try {
 27â†’        if (!existsSync(FONT_DIR)) mkdirSync(FONT_DIR, { recursive: true });
 28â†’
 29â†’        const downloads = [];
 30â†’        if (!existsSync(FONT_PATH)) {
 31â†’            downloads.push(
 32â†’                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans.ttf')
 33â†’                    .then(r => { if (!r.ok) throw new Error(`Font fetch failed: ${r.status}`); return r.arrayBuffer(); })
 34â†’                    .then(buf => writeFileSync(FONT_PATH, Buffer.from(buf)))
 35â†’            );
 36â†’        }
 37â†’        if (!existsSync(FONT_BOLD_PATH)) {
 38â†’            downloads.push(
 39â†’                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans-Bold.ttf')
 40â†’                    .then(r => { if (!r.ok) throw new Error(`Bold font fetch failed: ${r.status}`); return r.arrayBuffer(); })
 41â†’                    .then(buf => writeFileSync(FONT_BOLD_PATH, Buffer.from(buf)))
 42â†’            );
 43â†’        }
 44â†’        if (downloads.length) await Promise.all(downloads);
 45â†’
 46â†’        fontsReady = true;
 47â†’        console.log('Share fonts ready:', FONT_DIR);
 48â†’    } catch (err) {
 49â†’        console.error('Failed to setup share fonts:', err?.message || err);
 50â†’    }
 51â†’}
