 53â†’const app = express();
 54â†’const PORT = process.env.PORT || 3000;
 55â†’const SITE_URL = SITE_URL_SHARED;
 56â†’const DEFAULT_OG_IMAGE_URL = `${SITE_URL}/assets/no-image.png`;
 57â†’const DEFAULT_OG_IMAGE_WIDTH = 1200;
 58â†’const DEFAULT_OG_IMAGE_HEIGHT = 630;
 59â†’const SOCIAL_PREVIEW_MAX_CHARS = 160;
 60â†’const REMOTE_IMAGE_FETCH_TIMEOUT_MS = 7000;
 61â†’const REMOTE_IMAGE_MAX_BYTES = 15 * 1024 * 1024;
 62â†’const SHARE_IMAGE_FETCH_USER_AGENT = 'IskrybShareBot/1.0 (+https://iskrib.com)';
 63â†’const META_FB_APP_ID = (process.env.META_FB_APP_ID || process.env.FB_APP_ID || process.env.VITE_FB_APP_ID || '').trim();
 64â†’const SHARE_IMAGE_DEBUG = false;
 65â†’const SUPABASE_URL = (process.env.SUPABASE_URL || '').trim();
 66â†’
 67â†’const normalizeWhitespace = (value) => String(value ?? '')
 68â†’    .replace(/\s+/g, ' ')
 69â†’    .trim();
 70â†’
 71â†’const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 72â†’    const normalized = normalizeWhitespace(value);
 73â†’    if (!normalized) return '';
 74â†’    if (normalized.length <= maxLength) return normalized;
 75â†’    if (maxLength <= 3) return normalized.slice(0, maxLength);
 76â†’    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 77â†’};
 78â†’
 79â†’const escHtml = (str) => String(str)
 80â†’    .replace(/&/g, '&amp;')
 81â†’    .replace(/</g, '&lt;')
 82â†’    .replace(/>/g, '&gt;')
 83â†’    .replace(/"/g, '&quot;');
