 85â†’const makePostUrl = makePostUrlShared;
 86â†’
 87â†’const getRequestOrigin = (req) => {
 88â†’    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 89â†’    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 90â†’    const host = forwardedHost || req.get('host') || '';
 91â†’    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 92â†’    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 93â†’        ? forwardedProto
 94â†’        : requestProtocol === 'http' || requestProtocol === 'https'
 95â†’            ? requestProtocol
 96â†’            : 'https';
 97â†’
 98â†’    if (!host) {
 99â†’        return SITE_URL;
100â†’    }
101â†’
102â†’    return `${protocol}://${host}`;
103â†’};
104â†’
105â†’const pickFirstNonEmptyString = (...values) => {
106â†’    for (const value of values) {
107â†’        if (typeof value === 'string') {
108â†’            const trimmed = value.trim();
109â†’            if (trimmed) return trimmed;
110â†’        }
111â†’    }
112â†’    return '';
113â†’};
114â†’
115â†’const parseImageDimension = (value) => {
116â†’    const parsed = Number(value);
117â†’    if (!Number.isFinite(parsed)) return undefined;
118â†’    return parsed;
119â†’};
120â†’
121â†’const imageFromNodeLike = (nodeLike) => {
122â†’    if (!nodeLike || typeof nodeLike !== 'object') return null;
123â†’
124â†’    const src = pickFirstNonEmptyString(
125â†’        nodeLike.src,
126â†’        nodeLike.url,
127â†’        nodeLike.image_url,
128â†’        nodeLike.imageUrl,
129â†’        nodeLike?.payload?.src,
130â†’        nodeLike?.data?.src
131â†’    );
132â†’    if (!src) return null;
133â†’
134â†’    return {
135â†’        src,
136â†’        width: parseImageDimension(nodeLike.width),
137â†’        height: parseImageDimension(nodeLike.height),
138â†’    };
139â†’};
