141â†’const extractFromLexical = (contentJson) => {
142â†’    try {
143â†’        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
144â†’        const texts = [];
145â†’        let firstImage = null;
146â†’
147â†’        const walk = (node) => {
148â†’            if (!node || typeof node !== 'object') return;
149â†’
150â†’            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
151â†’            if (nodeType === 'text' && typeof node.text === 'string') {
152â†’                texts.push(node.text);
153â†’            }
154â†’
155â†’            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
156â†’            if (!firstImage && isImageNode) {
157â†’                const image = imageFromNodeLike(node);
158â†’                if (image) {
159â†’                    firstImage = image;
160â†’                }
161â†’            }
162â†’
163â†’            if (Array.isArray(node.children)) {
164â†’                node.children.forEach(walk);
165â†’            }
166â†’        };
167â†’
168â†’        if (parsed?.root) {
169â†’            walk(parsed.root);
170â†’        }
171â†’
172â†’        return {
173â†’            text: normalizeWhitespace(texts.join(' ')),
174â†’            image: firstImage
175â†’        };
176â†’    } catch {
177â†’        return { text: '', image: null };
178â†’    }
179â†’};
180â†’
181â†’const extractFromCanvasDoc = (canvasDocRaw) => {
182â†’    try {
183â†’        const doc = typeof canvasDocRaw === 'string' ? JSON.parse(canvasDocRaw) : canvasDocRaw;
184â†’        const text = Array.isArray(doc?.snippets)
185â†’            ? normalizeWhitespace(
186â†’                doc.snippets
187â†’                    .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text : ''))
188â†’                    .join(' ')
189â†’            )
190â†’            : '';
191â†’
192â†’        let image = null;
193â†’        if (Array.isArray(doc?.images)) {
194â†’            const first = doc.images.find((img) => imageFromNodeLike(img));
195â†’            if (first) image = imageFromNodeLike(first);
196â†’        }
197â†’
198â†’        return { text, image };
199â†’    } catch {
200â†’        return { text: '', image: null };
201â†’    }
202â†’};
203â†’
204â†’const buildShareMetaFromJournal = (journal) => {
205â†’    const lexicalData = extractFromLexical(journal?.content);
206â†’    const canvasData = extractFromCanvasDoc(journal?.canvas_doc);
207â†’    const normalizedTitle = typeof journal?.title === 'string' ? normalizeWhitespace(journal.title) : '';
208â†’    const title = normalizedTitle || 'Untitled Post';
209â†’    const authorName = normalizeWhitespace(journal?.users?.name) || 'Someone';
210â†’
211â†’    let description = lexicalData.text || '';
212â†’    if (!description && canvasData.text) {
213â†’        description = canvasData.text;
214â†’    }
215â†’    if (!description) {
216â†’        description = `Read "${title}" by ${authorName} on Iskryb`;
217â†’    }
218â†’
219â†’    let imageCandidate = DEFAULT_OG_IMAGE_URL;
220â†’    let imageCandidateSource = 'fallback';
221â†’    if (lexicalData.image?.src) {
222â†’        imageCandidate = lexicalData.image.src;
223â†’        imageCandidateSource = 'lexical';
224â†’    } else if (canvasData.image?.src) {
225â†’        imageCandidate = canvasData.image.src;
226â†’        imageCandidateSource = 'canvas';
227â†’    } else if (journal?.users?.image_url) {
228â†’        imageCandidate = journal.users.image_url;
229â†’        imageCandidateSource = 'author_avatar';
230â†’    }
231â†’
232â†’    return {
233â†’        title,
234â†’        normalizedTitle,
235â†’        description: toPreviewText(description),
236â†’        imageCandidate,
237â†’        imageCandidateSource
238â†’    };
239â†’};
