241â†’const resolveAbsoluteHttpUrl = (rawUrl) => {
242â†’    try {
243â†’        const raw = String(rawUrl || '').trim();
244â†’        if (!raw) return null;
245â†’
246â†’        const isSupabasePath =
247â†’            raw.startsWith('/storage/v1/object/public/')
248â†’            || raw.startsWith('storage/v1/object/public/');
249â†’
250â†’        const baseUrl = isSupabasePath && SUPABASE_URL
251â†’            ? `${SUPABASE_URL}/`
252â†’            : SITE_URL;
253â†’
254â†’        const parsed = new URL(raw, baseUrl);
255â†’        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
256â†’            return null;
257â†’        }
258â†’        return parsed.toString();
259â†’    } catch {
260â†’        return null;
261â†’    }
262â†’};
