264â†’const isPrivateIpv4Address = (ip) => {
265â†’    const parts = ip.split('.').map((part) => Number(part));
266â†’    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
267â†’        return true;
268â†’    }
269â†’
270â†’    const [a, b] = parts;
271â†’    if (a === 10 || a === 127 || a === 0) return true;
272â†’    if (a === 169 && b === 254) return true;
273â†’    if (a === 172 && b >= 16 && b <= 31) return true;
274â†’    if (a === 192 && b === 168) return true;
275â†’    return false;
276â†’};
277â†’
278â†’const isPrivateIpv6Address = (ip) => {
279â†’    const normalized = ip.toLowerCase();
280â†’    return (
281â†’        normalized === '::1' ||
282â†’        normalized.startsWith('fc') ||
283â†’        normalized.startsWith('fd') ||
284â†’        normalized.startsWith('fe80:')
285â†’    );
286â†’};
287â†’
288â†’const isPrivateIpAddress = (ip) => {
289â†’    const ipVersion = net.isIP(ip);
290â†’    if (ipVersion === 4) return isPrivateIpv4Address(ip);
291â†’    if (ipVersion === 6) return isPrivateIpv6Address(ip);
292â†’    return true;
293â†’};
