295â†’const isSafeRemoteImageUrl = (imageUrl) => {
296â†’    try {
297â†’        const parsed = new URL(imageUrl);
298â†’        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
299â†’            return false;
300â†’        }
301â†’
302â†’        const hostname = parsed.hostname.toLowerCase();
303â†’        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
304â†’            return false;
305â†’        }
306â†’
307â†’        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
308â†’            return false;
309â†’        }
310â†’
311â†’        return true;
312â†’    } catch {
313â†’        return false;
314â†’    }
315â†’};
316â†’
317â†’const evaluateShareImageCandidate = (rawUrl) => {
318â†’    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
319â†’    if (!absoluteUrl) {
320â†’        return {
321â†’            ok: false,
322â†’            reason: 'invalid_or_non_http_url',
323â†’            resolvedUrl: null,
324â†’        };
325â†’    }
326â†’
327â†’    let path = '';
328â†’    try {
329â†’        const parsed = new URL(absoluteUrl);
330â†’        path = String(parsed.pathname || '').toLowerCase();
331â†’    } catch {
332â†’        return {
333â†’            ok: false,
334â†’            reason: 'invalid_resolved_url',
335â†’            resolvedUrl: null,
336â†’        };
337â†’    }
338â†’
339â†’    if (path.endsWith('.svg')) {
340â†’        return {
341â†’            ok: false,
342â†’            reason: 'svg_not_supported_for_share_image',
343â†’            resolvedUrl: absoluteUrl,
344â†’        };
345â†’    }
346â†’
347â†’    if (!isSafeRemoteImageUrl(absoluteUrl)) {
348â†’        return {
349â†’            ok: false,
350â†’            reason: 'unsafe_remote_url',
351â†’            resolvedUrl: absoluteUrl,
352â†’        };
353â†’    }
354â†’
355â†’    return {
356â†’        ok: true,
357â†’        reason: 'ok',
358â†’        resolvedUrl: absoluteUrl,
359â†’    };
360â†’};
