421â†’const convertToOgJpeg = async (inputBuffer) => {
422â†’    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
423â†’        .rotate()
424â†’        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
425â†’            fit: 'contain',
426â†’            background: { r: 255, g: 255, b: 255, alpha: 1 },
427â†’        })
428â†’        .jpeg({ quality: 82, mozjpeg: true })
429â†’        .toBuffer();
430â†’};
