432â†’const getShareJournal = async (journalId) => {
433â†’    const { data: journal, error } = await supabase
434â†’        .from('journals')
435â†’        .select('id, title, content, post_type, canvas_doc, created_at, users(name, image_url)')
436â†’        .eq('id', journalId)
437â†’        .single();
438â†’
439â†’    if (error || !journal) {
440â†’        return null;
441â†’    }
442â†’
443â†’    return journal;
444â†’};
