473â†’app.use((req, res, next) => {
474â†’    if (req.method === "GET" && !req.headers.authorization) {
475â†’        // no-cache: browser must revalidate with server before using cached response.
476â†’        // This prevents stale data after mutations (likes, comments, replies, etc.)
477â†’        // while still allowing conditional requests (304 Not Modified) for performance.
478â†’        // React Query handles client-side caching, so browser cache is unnecessary.
479â†’        res.set("Cache-Control", "no-cache");
480â†’    }
481â†’    next();
482â†’});
