487â†’// â”€â”€ Profile share route: composite OG image for social media â”€â”€
488â†’app.get('/share/u/:username/image', async (req, res) => {
489â†’    const { username } = req.params;
490â†’    await ensureShareFonts();
491â†’
492â†’    try {
493â†’        const result = await getUserByUsernameService(username);
494â†’        const user = result?.userData?.[0];
495â†’        if (!user) {
496â†’            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
497â†’        }
498â†’
499â†’        const displayName = normalizeWhitespace(user.name) || username;
500â†’        const handle = `@${normalizeWhitespace(user.username || username)}`;
501â†’        const bio = toPreviewText(user.bio || '', 120);
502â†’
503â†’        // â”€â”€ Fetch background image â”€â”€
504â†’        let bgBuffer = null;
505â†’        const bgStyle = user.background || {};
506â†’        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
507â†’            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
508â†’            : null;
509â†’        const bgImageUrl = bgImageMatch?.[1];
510â†’
511â†’        if (bgImageUrl) {
512â†’            const bgEval = evaluateShareImageCandidate(bgImageUrl);
513â†’            if (bgEval.ok && bgEval.resolvedUrl) {
514â†’                try {
515â†’                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
516â†’                    bgBuffer = remote.buffer;
517â†’                } catch { /* use fallback gradient */ }
518â†’            }
519â†’        }
520â†’
521â†’        // â”€â”€ Base layer: background or dark gradient â”€â”€
522â†’        let baseLayer;
523â†’        if (bgBuffer) {
524â†’            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
525â†’                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
526â†’                .toBuffer();
527â†’        } else {
528â†’            // Use profile's solid background color if available, otherwise dark fallback
529â†’            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
530â†’                ? bgStyle.background.trim()
531â†’                : null;
532â†’            const gradientSvg = solidColor
533â†’                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
534â†’                    <rect width="100%" height="100%" fill="${solidColor}"/>
535â†’                </svg>`
536â†’                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
537â†’                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
538â†’                        <stop offset="0%" stop-color="#1a1a2e"/>
539â†’                        <stop offset="100%" stop-color="#16213e"/>
540â†’                    </linearGradient></defs>
