  5â†’const updateInfiniteJournalsCache = (old, updater) => {
  6â†’    if (!old || !Array.isArray(old.pages)) return old;
  7â†’
  8â†’    return {
  9â†’        ...old,
 10â†’        pages: old.pages.map((page) => ({
 11â†’            ...page,
 12â†’            data: Array.isArray(page?.data) ? page.data.map(updater) : page?.data,
 13â†’        })),
 14â†’    };
 15â†’};
