 17â†’const normalizeInteractionFlag = (value) => {
 18â†’    if(typeof value === 'boolean') return value;
 19â†’    if(typeof value === 'string'){
 20â†’        const normalized = value.trim().toLowerCase();
 21â†’        if(normalized === 'true') return true;
 22â†’        if(normalized === 'false') return false;
 23â†’    }
 24â†’    if(typeof value === 'number'){
 25â†’        return value === 1;
 26â†’    }
 27â†’    return Boolean(value);
 28â†’};
 29â†’
 30â†’const normalizeCount = (value) => {
 31â†’    const number = Number(value);
 32â†’    if(!Number.isFinite(number) || number < 0){
 33â†’        return 0;
 34â†’    }
 35â†’    return number;
 36â†’};
 37â†’
 38â†’const getNextToggleCount = (isActive, currentCount) => {
 39â†’    return isActive
 40â†’        ? Math.max(0, currentCount - 1)
 41â†’        : currentCount + 1;
 42â†’};
