 51â†’export const useBookMarkMutation = (session, userId) => {
 52â†’    const queryClient = useQueryClient();
 53â†’    const inFlightBookmarkIdsRef = useRef(new Set());
 54â†’
 55â†’    const mutation = useMutation({
 56â†’        mutationFn: (data) => addBookmark(session?.access_token, data),
 57â†’
 58â†’        onMutate: async(data) =>{
 59â†’            queryClient.cancelQueries({ queryKey: ['journals'] });
 60â†’            queryClient.cancelQueries({ queryKey: ['userJournals'] });
 61â†’            queryClient.cancelQueries({ queryKey: ['visitedProfileJournals'] });
 62â†’
 63â†’            const previousData = [
 64â†’                ...queryClient.getQueriesData({ queryKey: ['journals'] }),
 65â†’                ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
 66â†’                ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
 67â†’            ];
 68â†’
 69â†’            const updater = (journal) => {
 70â†’                if(journal.id !== data.journalId) return journal;
 71â†’
 72â†’                const isBookmarked = normalizeInteractionFlag(journal?.has_bookmarked);
 73â†’                const count = normalizeCount(journal?.bookmark_count?.[0]?.count);
 74â†’                const nextCount = getNextToggleCount(isBookmarked, count);
 75â†’
 76â†’                return{
 77â†’                    ...journal,
 78â†’                    has_bookmarked: !isBookmarked,
 79â†’                    bookmark_count: [{count: nextCount}]
 80â†’                };
 81â†’            };
 82â†’
 83â†’            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => updateInfiniteJournalsCache(old, updater));
 84â†’            queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
 85â†’            queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
 86â†’
 87â†’            return {previousData};
 88â†’        },
 89â†’        onError: (err,data, context) =>{
 90â†’            context?.previousData?.forEach(([key, value]) => {
 91â†’                queryClient.setQueryData(key, value);
 92â†’            });
 93â†’        },
 94â†’        onSettled: () =>{
 95â†’            queryClient.invalidateQueries({ queryKey: ['journals'] });
 96â†’            queryClient.invalidateQueries({ queryKey: ['userJournals'] });
 97â†’            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
 98â†’        }
 99â†’    });
100â†’
101â†’    const guardedMutate = (variables, options) => {
102â†’        const journalKey = toJournalKey(variables?.journalId);
103â†’        if(journalKey && inFlightBookmarkIdsRef.current.has(journalKey)){
104â†’            return;
105â†’        }
106â†’
107â†’        if(journalKey){
108â†’            inFlightBookmarkIdsRef.current.add(journalKey);
109â†’        }
110â†’
111â†’        mutation.mutate(variables, {
112â†’            ...options,
113â†’            onSettled: (data, error, vars, context) => {
114â†’                if(journalKey){
115â†’                    inFlightBookmarkIdsRef.current.delete(journalKey);
116â†’                }
117â†’                options?.onSettled?.(data, error, vars, context);
118â†’            }
119â†’        });
120â†’    };
121â†’
122â†’    const guardedMutateAsync = async (variables, options) => {
123â†’        const journalKey = toJournalKey(variables?.journalId);
124â†’        if(journalKey && inFlightBookmarkIdsRef.current.has(journalKey)){
125â†’            return {message: 'skipped'};
126â†’        }
127â†’
128â†’        if(journalKey){
129â†’            inFlightBookmarkIdsRef.current.add(journalKey);
130â†’        }
131â†’
132â†’        try {
133â†’            return await mutation.mutateAsync(variables, options);
134â†’        } finally {
135â†’            if(journalKey){
136â†’                inFlightBookmarkIdsRef.current.delete(journalKey);
137â†’            }
138â†’        }
139â†’    };
140â†’
141â†’    return {
