238â†’export const repostService = async(sourceJournalId, caption, userId) => {
239â†’    if(!sourceJournalId || !userId){
240â†’        throw {status: 400, error: 'sourceJournalId or userId is undefined'};
241â†’    }
242â†’
243â†’    if(caption && caption.length > 280){
244â†’        throw {status: 400, error: 'caption must be 280 characters or less'};
245â†’    }
246â†’
247â†’    // Fetch source journal
248â†’    const {data: sourceJournal, error: errorSourceJournal} = await supabase
249â†’        .from('journals')
250â†’        .select('id, title, user_id, privacy, is_repost, repost_source_journal_id')
251â†’        .eq('id', sourceJournalId)
252â†’        .maybeSingle();
253â†’
254â†’    if(errorSourceJournal){
255â†’        console.error('supabase error while fetching source journal:', errorSourceJournal.message);
256â†’        throw {status: 500, error: 'supabase error while fetching source journal'};
257â†’    }
258â†’
259â†’    if(!sourceJournal){
260â†’        throw {status: 404, error: 'source journal not found'};
261â†’    }
262â†’
263â†’    if(sourceJournal.privacy !== 'public'){
264â†’        throw {status: 403, error: 'cannot repost a private post'};
265â†’    }
266â†’
267â†’    if(sourceJournal.user_id === userId){
268â†’        throw {status: 403, error: 'cannot repost your own post'};
269â†’    }
270â†’
271â†’    // If reposting a repost, follow chain to the ultimate original
272â†’    let ultimateSourceId = sourceJournalId;
273â†’    let ultimateSourceUserId = sourceJournal.user_id;
274â†’    let ultimateSourceTitle = sourceJournal.title;
275â†’
276â†’    if(sourceJournal.is_repost && sourceJournal.repost_source_journal_id){
277â†’        const {data: originalJournal, error: errorOriginal} = await supabase
278â†’            .from('journals')
279â†’            .select('id, title, user_id, privacy')
280â†’            .eq('id', sourceJournal.repost_source_journal_id)
281â†’            .maybeSingle();
282â†’
283â†’        if(errorOriginal){
284â†’            console.error('supabase error fetching original:', errorOriginal.message);
285â†’            throw {status: 500, error: 'supabase error while fetching original post'};
286â†’        }
287â†’        if(!originalJournal){
288â†’            throw {status: 404, error: 'original post no longer exists'};
289â†’        }
290â†’        if(originalJournal.privacy !== 'public'){
291â†’            throw {status: 403, error: 'cannot repost a private post'};
292â†’        }
293â†’        if(originalJournal.user_id === userId){
294â†’            throw {status: 403, error: 'cannot repost your own post'};
295â†’        }
296â†’
297â†’        ultimateSourceId = originalJournal.id;
298â†’        ultimateSourceUserId = originalJournal.user_id;
299â†’        ultimateSourceTitle = originalJournal.title;
300â†’    }
301â†’
302â†’    // Check for duplicate repost
303â†’    const {data: existingRepost, error: errorExisting} = await supabase
304â†’        .from('journals')
305â†’        .select('id')
306â†’        .eq('user_id', userId)
307â†’        .eq('repost_source_journal_id', ultimateSourceId)
308â†’        .eq('is_repost', true)
309â†’        .maybeSingle();
310â†’
311â†’    if(errorExisting){
312â†’        console.error('supabase error while checking existing repost:', errorExisting.message);
313â†’        throw {status: 500, error: 'supabase error while checking existing repost'};
314â†’    }
315â†’
316â†’    if(existingRepost){
317â†’        throw {status: 409, error: 'you have already reposted this post'};
318â†’    }
319â†’
320â†’    const repostTitle = `Repost: ${ultimateSourceTitle || 'Untitled'}`;
321â†’
322â†’    const {data: insertedRepost, error: errorInsertRepost} = await supabase
323â†’        .from('journals')
324â†’        .insert({
325â†’            user_id: userId,
326â†’            is_repost: true,
327â†’            repost_source_journal_id: ultimateSourceId,
328â†’            repost_caption: caption || null,
329â†’            post_type: 'text',
330â†’            content: null,
331â†’            title: repostTitle.length > 255 ? repostTitle.substring(0, 255) : repostTitle,
332â†’            privacy: 'public'
333â†’        })
334â†’        .select('id')
335â†’        .single();
336â†’
337â†’    if(errorInsertRepost){
338â†’        console.error('supabase error while inserting repost:', errorInsertRepost.message);
339â†’        throw {status: 500, error: 'supabase error while inserting repost'};
340â†’    }
341â†’
342â†’    // Notify the original author (skip if self)
343â†’    const isOwnContent = userId === ultimateSourceUserId;
344â†’    if(!isOwnContent){
345â†’        const {error: errorNotif} = await supabase
346â†’            .from('notifications')
347â†’            .insert({
348â†’                sender_id: userId,
349â†’                receiver_id: ultimateSourceUserId,
350â†’                journal_id: ultimateSourceId,
351â†’                repost_journal_id: insertedRepost.id,
352â†’                type: 'repost',
353â†’                read: false
354â†’            });
355â†’
356â†’        if(errorNotif){
357â†’            console.error('supabase error while inserting repost notification:', errorNotif.message);
358â†’        }
359â†’    }
360â†’
361â†’    return {message: 'repost created', repostId: insertedRepost.id, sourceJournalId: ultimateSourceId};
362â†’}
