 86â†’            const children = root.getChildren();
 87â†’
 88â†’            const hasEnoughParagraphNodes = children.length > 1
 89â†’            const hasParargraphSize = children[0]?.__size > 0
 90â†’
 91â†’            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
 92â†’            setHasContent(hasContent);
 93â†’
