 30â†’const normalizeInteractionFlag = (value) => {
 31â†’    if(typeof value === 'boolean') return value;
 32â†’    if(typeof value === 'string'){
 33â†’        const normalized = value.trim().toLowerCase();
 34â†’        if(normalized === 'true') return true;
 35â†’        if(normalized === 'false') return false;
 36â†’    }
 37â†’    if(typeof value === 'number'){
 38â†’        return value === 1;
 39â†’    }
 40â†’    return Boolean(value);
 41â†’};
 42â†’
 43â†’const normalizeCount = (value) => {
 44â†’    const number = Number(value);
 45â†’    if(!Number.isFinite(number) || number < 0){
 46â†’        return 0;
 47â†’    }
 48â†’    return number;
 49â†’};
