135â†’export const getSeoForPath = (pathname) => {
136â†’  const normalized = pathname || "/";
137â†’  const exactMatch = SEO_ROUTES.find((route) => route.path === normalized);
138â†’  if (exactMatch) {
139â†’    return { ...DEFAULT_SEO, ...exactMatch };
140â†’  }
141â†’
142â†’  const dynamicMatch = DYNAMIC_PATTERNS.find((entry) => entry.test(normalized));
143â†’  if (dynamicMatch) {
144â†’    const seo = typeof dynamicMatch.seo === "function"
145â†’      ? dynamicMatch.seo(normalized)
146â†’      : dynamicMatch.seo;
147â†’    return { ...DEFAULT_SEO, ...seo };
148â†’  }
149â†’
150â†’  return { ...DEFAULT_SEO };
151â†’};
