  8â†’const POST_TYPE_TEXT = 'text';
  9â†’const POST_TYPE_CANVAS = 'canvas';
 10â†’
 11â†’const simpleHash = (str) => {
 12â†’    let h = 0;
 13â†’    for(let i = 0; i < str.length; i++){
 14â†’        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
 15â†’    }
 16â†’    return h;
 17â†’};
 18â†’
 19â†’const userHomeCoords = (userId) => {
 20â†’    const mid = Math.floor(userId.length / 2);
 21â†’    const xHash = Math.abs(simpleHash(userId.slice(0, mid)));
 22â†’    const yHash = Math.abs(simpleHash(userId.slice(mid)));
 23â†’    const x = (xHash % 50001) / 50000 * 50000 - 25000;
 24â†’    const y = (yHash % 50001) / 50000 * 50000 - 25000;
 25â†’    return {x, y};
 26â†’};
 27â†’
 28â†’const spiralLayout = (index) => {
 29â†’    if(index === 0) return {dx: 0, dy: 0};
 30â†’    const angle = index * 0.8;
 31â†’    const radius = 30 * Math.sqrt(index);
 32â†’    return {dx: radius * Math.cos(angle), dy: radius * Math.sin(angle)};
 33â†’};
 34â†’
 35â†’const normalizePostType = (postType) => {
 36â†’    if(typeof postType !== 'string'){
 37â†’        return POST_TYPE_TEXT;
 38â†’    }
 39â†’
 40â†’    const normalized = postType.trim().toLowerCase();
 41â†’    return normalized === POST_TYPE_CANVAS ? POST_TYPE_CANVAS : POST_TYPE_TEXT;
 42â†’}
