 44â†’const parseCanvasDocInput = (canvasDoc) => {
 45â†’    if(!canvasDoc){
 46â†’        return null;
 47â†’    }
 48â†’
 49â†’    const parsedCanvasDoc = typeof canvasDoc === 'string' ? JSON.parse(canvasDoc) : canvasDoc;
 50â†’    if(!parsedCanvasDoc || typeof parsedCanvasDoc !== 'object'){
 51â†’        throw new Error('canvas_doc should be a valid object');
 52â†’    }
 53â†’
 54â†’    if(!Array.isArray(parsedCanvasDoc.snippets)){
 55â†’        throw new Error('canvas_doc.snippets should be an array');
 56â†’    }
 57â†’
 58â†’    return parsedCanvasDoc;
 59â†’}
