 61â†’const extractCanvasPlainText = (canvasDoc) => {
 62â†’    if(!canvasDoc || !Array.isArray(canvasDoc.snippets)){
 63â†’        return '';
 64â†’    }
 65â†’
 66â†’    return canvasDoc.snippets
 67â†’        .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text.trim() : ''))
 68â†’        .filter(Boolean)
 69â†’        .join(' ');
