254â†’    remixSourceJournalId = null,
255â†’    isRemix = false
256â†’) =>{
257â†’    if(!userId){
258â†’        console.error('userId is undefined');
259â†’        throw {status: 400, error: 'userId is undefined'};
260â†’    }
261â†’
262â†’    const resolvedPostType = normalizePostType(postType);
263â†’    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
264â†’
265â†’    if(!trimmedTitle){
266â†’        console.error('title is missing!');
267â†’        throw {status: 400, error: 'title is missing!'};
268â†’    }
269â†’
270â†’    let embeddingBody = '';
271â†’    const shouldSaveRemixMetadata = Boolean(
272â†’        remixSourceJournalId
273â†’        && typeof remixSourceJournalId === 'string'
274â†’        && remixSourceJournalId.trim()
275â†’    );
276â†’    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
277â†’    let payload = {
278â†’        user_id: userId,
279â†’        title: trimmedTitle,
280â†’        post_type: resolvedPostType
281â†’    };
282â†’
283â†’    if(resolvedPostType === POST_TYPE_CANVAS){
284â†’        let parsedCanvasDoc = null;
285â†’        try {
286â†’            parsedCanvasDoc = parseCanvasDocInput(canvasDocInput);
287â†’        } catch (error) {
288â†’            console.error('invalid canvas doc on insert:', error?.message || error);
289â†’            throw {status: 400, error: 'invalid canvas_doc'};
290â†’        }
291â†’
292â†’        if(!parsedCanvasDoc){
293â†’            console.error('canvas_doc is missing for canvas post');
294â†’            throw {status: 400, error: 'canvas_doc is missing'};
295â†’        }
296â†’
297â†’        embeddingBody = extractCanvasPlainText(parsedCanvasDoc);
298â†’        payload = {
299â†’            ...payload,
300â†’            content: null,
301â†’            canvas_doc: parsedCanvasDoc
302â†’        };
303â†’    } else {
304â†’        if(!content){
305â†’            console.error('content is missing for text post!');
306â†’            throw {status: 400, error: 'content is missing for text post'};
307â†’        }
308â†’
309â†’        const parseData = parseTextContentSafely(content);
310â†’        if(!parseData){
311â†’            console.error('error while parsing text content data');
312â†’            throw {status: 400, error: 'error while parsing text content data'};
313â†’        }
314â†’
315â†’        embeddingBody = parseData.wholeText || '';
316â†’        payload = {
317â†’            ...payload,
318â†’            content: content,
319â†’            canvas_doc: null
320â†’        };
321â†’    }
322â†’
323â†’    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
324â†’
325â†’    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
326â†’        console.error('error while generating embeddings on a post!');
327â†’        throw {status: 400, error: 'error while generating embeddings on a post!'};
328â†’    }
329â†’
330â†’    const insertPayload = {
331â†’        ...payload,
332â†’        embeddings: embeddingResult
333â†’    };
334â†’
335â†’    if(normalizedIsRemix){
336â†’        insertPayload.is_remix = true;
337â†’    }
