 40â†’const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, onSwitchToCanvas}) => {
 41â†’    const [editor] = useLexicalComposerContext();
 42â†’    const [editorState, setEditorState] = useState(null);
 43â†’    const [hasContent, setHasContent] = useState(false);
 44â†’    const [isSending, setIsSending] = useState(false);
 45â†’
 46â†’    const {session, user} = useAuth();
 47â†’
 48â†’    const queryClient = useQueryClient();
 49â†’
 50â†’    const handleClickSave = async(e, title) =>{
 51â†’        e.stopPropagation();
 52â†’        setIsSending(true)
 53â†’        try {
 54â†’            const formdata = new FormData();
 55â†’            if(title && editorState){
 56â†’                formdata.append('title', title)
 57â†’                formdata.append('content', editorState)
 58â†’            }
 59â†’            const saveData = await saveJournal(session?.access_token, formdata)
 60â†’
 61â†’            if(saveData){
 62â†’                console.log(saveData)
 63â†’                queryClient.invalidateQueries({queryKey: ['journals']});
 64â†’                queryClient.invalidateQueries({queryKey: ['userJournals', user?.userData?.[0].id]})
 65â†’            }
 66â†’
 67â†’            setIsSending(false)
 68â†’        } catch (error) {
 69â†’            console.error("Error saving journal:", error);
 70â†’        }finally {
 71â†’            setIsSending(false)
 72â†’            setHasContent(false)
 73â†’            onCloseOnSave();
 74â†’            addUploadImagesPath([])
 75â†’        }
 76â†’
 77â†’    }
 78â†’
 79â†’    const onchange = useCallback((state) => {
 80â†’        const jsonb = JSON.stringify(state.toJSON());
 81â†’        setEditorState(jsonb)
 82â†’
 83â†’        state.read(() => {
 84â†’            const root = $getRoot();
 85â†’
 86â†’            const children = root.getChildren();
 87â†’
 88â†’            const hasEnoughParagraphNodes = children.length > 1
 89â†’            const hasParargraphSize = children[0]?.__size > 0
 90â†’
 91â†’            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
 92â†’            setHasContent(hasContent);
 93â†’
 94â†’            // Calculate word count
 95â†’            const text = root.getTextContent().trim();
 96â†’            const words = text ? text.split(/\s+/).length : 0;
 97â†’            setWordCount(words);
 98â†’        })
 99â†’    }, [setWordCount])
100â†’
101â†’    return(
102â†’        <>
103â†’        {/* Toolbar above content */}
104â†’        <div className="toolbar-wrapper">
105â†’            <ToolBar addUploadedImagePath={addUploadImagesPath} onSwitchToCanvas={onSwitchToCanvas}/>
106â†’        </div>
107â†’
108â†’        {/* Bar loader directly under toolbar */}
109â†’        <div className="editor-loader-wrapper">
110â†’            {isSending && (
111â†’                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
112â†’            )}
113â†’        </div>
114â†’
115â†’        {/* Editor content area */}
116â†’        <div className="editor-shell">
117â†’            <RichTextPlugin
118â†’            contentEditable={
119â†’            <ContentEditable
120â†’            className="editor-input"
121â†’            aria-placeholder="Write your thoughts here..."
122â†’            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
123â†’            }
124â†’            ErrorBoundary={LexicalErrorBoundary}
125â†’            />
126â†’
127â†’            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
128â†’            <HistoryPlugin/>
129â†’            <OnChangePlugin onChange={onchange}/>
130â†’
131â†’        </div>
132â†’
133â†’        {/* Footer: word count + save */}
134â†’        <div className='editor-footer'>
135â†’            <span className="editor-word-count">
136â†’                {wordCount} {wordCount === 1 ? 'word' : 'words'}
137â†’            </span>
138â†’            <button disabled={!title || !hasContent || isSending} onClick={(e) =>handleClickSave(e, title)} className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}>
139â†’                Share
140â†’            </button>
141â†’        </div>
142â†’        </>
143â†’    )
144â†’}
145â†’
146â†’export default EditorInner;
