362â†’const fetchRemoteImageBuffer = async (imageUrl) => {
363â†’    const controller = new AbortController();
364â†’    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
365â†’
366â†’    try {
367â†’        const response = await fetch(imageUrl, {
368â†’            method: 'GET',
369â†’            redirect: 'follow',
370â†’            signal: controller.signal,
371â†’            headers: {
372â†’                Accept: 'image/*,*/*;q=0.8',
373â†’                'Accept-Encoding': 'identity',
374â†’                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
375â†’            },
376â†’        });
377â†’
378â†’        if (!response.ok) {
379â†’            throw new Error(`upstream image status ${response.status}`);
380â†’        }
381â†’
382â†’        const finalUrl = response.url || imageUrl;
383â†’        if (!isSafeRemoteImageUrl(finalUrl)) {
384â†’            throw new Error('upstream redirected to unsafe url');
385â†’        }
386â†’
387â†’        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
388â†’        if (!contentType.startsWith('image/')) {
389â†’            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
390â†’        }
391â†’        if (contentType.includes('image/svg')) {
392â†’            throw new Error('svg images are not used for share previews');
393â†’        }
394â†’
395â†’        const headerContentLength = Number(response.headers.get('content-length'));
396â†’        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
397â†’            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
398â†’        }
399â†’
400â†’        const arrayBuffer = await response.arrayBuffer();
401â†’        const buffer = Buffer.from(arrayBuffer);
402â†’
403â†’        if (!buffer.length) {
404â†’            throw new Error('upstream image is empty');
405â†’        }
406â†’        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
407â†’            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
408â†’        }
409â†’
410â†’        return {
411â†’            buffer,
412â†’            contentType,
413â†’            byteLength: buffer.length,
414â†’            finalUrl,
415â†’        };
416â†’    } finally {
417â†’        clearTimeout(timeout);
418â†’    }
419â†’};
