668â†’app.get('/share/post/:journalId/image', async (req, res) => {
669â†’    const { journalId } = req.params;
670â†’    await ensureShareFonts();
671â†’    const debugMode = isShareImageDebugRequest(req);
672â†’    const debugPayload = {
673â†’        ok: false,
674â†’        fallback: false,
675â†’        journalId,
676â†’        stage: 'start',
677â†’        reason: '',
678â†’        meta: {
679â†’            imageCandidateSource: null,
680â†’            imageCandidateRaw: null,
681â†’            imageCandidateResolved: null,
682â†’            upstreamFinalUrl: null,
683â†’            upstreamContentType: null,
684â†’            upstreamBytes: null,
685â†’            outputBytes: null,
686â†’        },
687â†’    };
688â†’
689â†’    const fallbackWithReason = (reason) => {
690â†’        debugPayload.ok = false;
691â†’        debugPayload.fallback = true;
692â†’        debugPayload.stage = 'fallback';
693â†’        debugPayload.reason = reason;
694â†’        if (debugMode) {
695â†’            return sendShareImageDebug(res, debugPayload);
696â†’        }
697â†’        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
698â†’    };
699â†’
700â†’    try {
701â†’        const journal = await getShareJournal(journalId);
702â†’        debugPayload.stage = 'journal_loaded';
703â†’        if (!journal) {
704â†’            return fallbackWithReason('journal_not_found');
705â†’        }
706â†’
707â†’        const shareMeta = buildShareMetaFromJournal(journal);
708â†’        debugPayload.stage = 'candidate_extracted';
709â†’        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
710â†’        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
711â†’
712â†’        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
713â†’        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
714â†’        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
715â†’            return fallbackWithReason(candidateEvaluation.reason);
716â†’        }
717â†’
718â†’        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
719â†’        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
720â†’            return fallbackWithReason('candidate_is_default_fallback');
721â†’        }
722â†’
723â†’        debugPayload.stage = 'fetching_upstream';
724â†’        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
725â†’        debugPayload.stage = 'upstream_loaded';
726â†’        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
727â†’        debugPayload.meta.upstreamContentType = remoteImage.contentType;
728â†’        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
729â†’
730â†’        debugPayload.stage = 'converting_image';
731â†’        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
732â†’        debugPayload.stage = 'converted_image';
733â†’        debugPayload.ok = true;
734â†’        debugPayload.reason = 'ok';
735â†’        debugPayload.meta.outputBytes = ogImageBuffer.length;
736â†’
737â†’        if (debugMode) {
738â†’            return sendShareImageDebug(res, debugPayload);
739â†’        }
740â†’
741â†’        res.set('Content-Type', 'image/jpeg');
742â†’        res.set('Cache-Control', 'public, max-age=3600');
743â†’        return res.send(ogImageBuffer);
744â†’    } catch (err) {
745â†’        debugPayload.stage = 'error';
746â†’        debugPayload.reason = err?.message || 'unknown_error';
747â†’        console.error('share image route error:', err?.message || err);
748â†’        return fallbackWithReason(debugPayload.reason);
749â†’    }
750â†’});
