 11â†’const incrementJournalCommentCount = (old, postId) => {
 12â†’    if (!old || !Array.isArray(old.pages)) return old;
 13â†’
 14â†’    return {
 15â†’        ...old,
 16â†’        pages: old.pages.map((page) => ({
 17â†’            ...page,
 18â†’            data: Array.isArray(page?.data)
 19â†’                ? page.data.map((journal) => {
 20â†’                    if (journal?.id !== postId) return journal;
 21â†’
 22â†’                    const currentCount = journal?.comment_count?.[0]?.count ?? 0;
 23â†’                    return {
 24â†’                        ...journal,
 25â†’                        comment_count: [{ count: currentCount + 1 }],
 26â†’                    };
 27â†’                })
 28â†’                : page?.data,
 29â†’        })),
 30â†’    };
 31â†’};
