 33â†’const CommentSection = ({onclose, postId, receiverId})=>{
 34â†’    const queryClient = useQueryClient();
 35â†’
 36â†’    const {session, user} = useAuth();
 37â†’
 38â†’    const textAreaFocusRef = useRef();
 39â†’
 40â†’    const [comments, setComments] = useState('');
