 42â†’
 43â†’    const {data, fetchNextPage, hasNextPage, isLoading, isFetchingNextPage} = useInfiniteQuery({
 44â†’        queryKey: ['postComments', postId],
 45â†’        queryFn: ({queryKey, pageParam = null}) => getComments(pageParam, 10, queryKey[1]),
 46â†’        getNextPageParam: (lastPage) => {
 47â†’            if(lastPage?.hasMore) {
 48â†’                const lastComment = lastPage.comments[lastPage?.comments?.length - 1];
 49â†’                return new Date(lastComment.created_at).toISOString();
 50â†’            } else {
 51â†’                return undefined;
 52â†’            }
 53â†’        },
 54â†’        refetchOnWindowFocus: false
 55â†’    })
 56â†’
 57â†’    const handleSeeMoreComments = (e) =>{
 58â†’        e.stopPropagation();
 59â†’        if(hasNextPage && !isFetchingNextPage){
 60â†’            try {
 61â†’                fetchNextPage()
 62â†’            } catch (error) {
 63â†’                throw new Error(error);
 64â†’            }
 65â†’        }
 66â†’    }
 67â†’
 68â†’    useEffect(() =>{
 69â†’        let timeout;
