 76â†’             clearTimeout(timeout);
 77â†’        }
 78â†’    }, [])
 79â†’
 80â†’    const handeCloseCommentsSection = (e) =>{
 81â†’        e.stopPropagation();
 82â†’        onclose()
 83â†’    }
 84â†’
 85â†’    const handaleSubmitComment = async(e, postId, receiverId) =>{
 86â†’        e.stopPropagation();
 87â†’        const trimmedComment = comments.trim();
 88â†’        if (!trimmedComment) return;
 89â†’
 90â†’        const optimisticComment = {
 91â†’            id: `optimistic-${Date.now()}`,
 92â†’            comment: trimmedComment,
 93â†’            created_at: new Date().toISOString(),
 94â†’            parent_id: null,
 95â†’            post_id: postId,
 96â†’            reply_count: 0,
 97â†’            user_id: user?.userData?.[0]?.id,
 98â†’            users: {
