100â†’                name: user?.userData?.[0]?.name,
101â†’                image_url: user?.userData?.[0]?.image_url,
102â†’                badge: user?.userData?.[0]?.badge,
103â†’            },
104â†’        };
105â†’
106â†’        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
107â†’        const previousComments = queryClient.getQueryData(['postComments', postId]);
108â†’        const previousJournalCaches = [
109â†’            ...queryClient.getQueriesData({ queryKey: ['journals'] }),
110â†’            ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
111â†’            ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
112â†’        ];
113â†’
114â†’        queryClient.setQueryData(['postComments', postId], (old) => {
115â†’            if (!old || !Array.isArray(old.pages)) {
116â†’                return {
117â†’                    pageParams: [null],
118â†’                    pages: [{ comments: [optimisticComment], hasMore: false }],
119â†’                };
120â†’            }
121â†’
122â†’            return {
123â†’                ...old,
124â†’                pages: old.pages.map((page, index) =>
125â†’                    index === 0
126â†’                        ? { ...page, comments: [optimisticComment, ...(page?.comments || [])] }
127â†’                        : page
128â†’                ),
129â†’            };
130â†’        });
131â†’
132â†’        queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => incrementJournalCommentCount(old, postId));
133â†’        queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => incrementJournalCommentCount(old, postId));
134â†’        queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => incrementJournalCommentCount(old, postId));
135â†’
136â†’        const body = {
137â†’            comments: trimmedComment,
138â†’            postId: postId,
139â†’            receiverId: receiverId,
140â†’        }
141â†’
142â†’        try {
143â†’            setIsSubmittingComment(true)
144â†’            const message = await addComment(session?.access_token, body);
145â†’            if(message){
146â†’                console.log(message)
147â†’            }
148â†’            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
149â†’            queryClient.invalidateQueries({ queryKey: ['journals'] });
150â†’            queryClient.invalidateQueries({ queryKey: ['userJournals'] });
151â†’            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
152â†’        } catch (error) {
153â†’            queryClient.setQueryData(['postComments', postId], previousComments);
154â†’            previousJournalCaches.forEach(([key, value]) => {
155â†’                queryClient.setQueryData(key, value);
156â†’            });
157â†’            throw new Error('error adding comments')
158â†’        } finally {
159â†’            setIsSubmittingComment(false)
160â†’            setComments('')
161â†’        }
162â†’    }
163â†’
164â†’    const commentsData = data?.pages?.flatMap((page) => page.comments || []);
165â†’
166â†’    return(
167â†’        <motion.div
168â†’            initial={{y: '100vh', opacity: 0}}
169â†’            animate={{
170â†’                y: 0,
171â†’                opacity: 1,
172â†’                transition: {type: 'spring', damping: 25, stiffness: 200}
173â†’            }}
174â†’            exit={{y: '-100vh', opacity: 0, transition: {duration: 0.2}}}
175â†’            className="cm-parent-container"
176â†’        >
177â†’            <div className="cm-header">
