180â†’                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px">
181â†’                        <path d="m336-280-56-56 144-144-144-143 56-56 144 144 143-144 56 56-144 143 144 144-56 56-143-144-144 144Z"/>
182â†’                    </svg>
183â†’                </div>
184â†’            </div>
185â†’
186â†’            <div className="cm-list">
187â†’                {isLoading ? (
188â†’                    <div className="cm-loading">
189â†’                        <MoonLoader color='rgba(19, 77, 104, 1)' size={20} loading={isLoading}/>
190â†’                    </div>
191â†’                ) : (
192â†’                    commentsData?.map((comment, index) => (
193â†’                        <CommentsCards postId={postId} key={comment?.id || index} comments={comment}/>
194â†’                    ))
195â†’                )}
196â†’
197â†’                {hasNextPage && (
