  25â†’const extractBearerToken = (authHeader = "") => {
  26â†’    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
  27â†’    if (!trimmed) return "";
  28â†’
  29â†’    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
  30â†’    if (bearerMatch?.[1]) {
  31â†’        return bearerMatch[1].trim();
  32â†’    }
  33â†’
  34â†’    return trimmed;
  35â†’};
  36â†’
  37â†’const resolveAuthUser = async (token) => {
  38â†’    if (!token) {
  39â†’        return { user: null, error: null };
  40â†’    }
  41â†’
  42â†’    const { data: authData, error: authError } = await supabase.auth.getUser(token);
  43â†’    if (authError || !authData?.user?.id) {
  44â†’        return { user: null, error: authError || new Error("missing user id") };
  45â†’    }
  46â†’
  47â†’    return { user: authData.user, error: null };
  48â†’};
  49â†’
  50â†’const requireAuth = async (req, res, next) => {
  51â†’    const token = extractBearerToken(req.headers?.authorization);
  52â†’    if (!token) {
  53â†’        return res.status(401).json({ error: 'not authorized' });
  54â†’    }
  55â†’
  56â†’    const { user, error } = await resolveAuthUser(token);
  57â†’    if (error || !user?.id) {
  58â†’        console.error('auth middleware error:', error?.message || 'missing user id');
  59â†’        return res.status(401).json({ error: 'not authorized' });
  60â†’    }
  61â†’
  62â†’    req.userId = user.id;
  63â†’    req.authUser = user;
  64â†’    return next();
  65â†’};
  66â†’
  67â†’const optionalAuth = async (req, _res, next) => {
  68â†’    const token = extractBearerToken(req.headers?.authorization);
  69â†’    if (!token) {
  70â†’        return next();
  71â†’    }
  72â†’
  73â†’    const { user } = await resolveAuthUser(token);
  74â†’    if (user?.id) {
  75â†’        req.userId = user.id;
  76â†’        req.authUser = user;
  77â†’    }
  78â†’
  79â†’    return next();
  80â†’};
