 259â†’router.get('/getNotifications', requireAuth, async(req, res) =>{
 260â†’    const {before, limit} = req.query;
 261â†’    const userId = req.userId;
 262â†’
 263â†’    // Fetch a generous amount from both tables, then merge and paginate
 264â†’    const fetchLimit = parseInt(limit) + 1;
 265â†’
 266â†’    let journalQuery = supabase
 267â†’    .from('notifications')
 268â†’    .select(
 269â†’        `*,
 270â†’        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count), users(name, id, image_url, badge)),
 271â†’        users!sender_id(name, user_email, image_url, id, badge),
 272â†’        constellation_id,
 273â†’        constellations!constellation_id(status, star_id_a, star_id_b)
 274â†’        `
 275â†’    )
 276â†’    .eq('receiver_id', userId)
 277â†’    .order('created_at', {ascending: false})
 278â†’    .order('id', {ascending: false})
 279â†’    .limit(fetchLimit)
 280â†’
 281â†’    let opinionQuery = supabase
 282â†’    .from('notification_opinions')
 283â†’    .select(
 284â†’        `*,
 285â†’        opinions!opinion_id(id, opinion, user_id, created_at, users(name, id, image_url, badge)),
 286â†’        users!sender_id(name, user_email, image_url, id, badge)
 287â†’        `
 288â†’    )
 289â†’    .eq('receiver_id', userId)
 290â†’    .order('created_at', {ascending: false})
 291â†’    .order('id', {ascending: false})
 292â†’    .limit(fetchLimit)
 293â†’
 294â†’    if(before){
 295â†’        journalQuery = journalQuery.lt('created_at', before);
 296â†’        opinionQuery = opinionQuery.lt('created_at', before);
 297â†’    }
 298â†’
 299â†’    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 300â†’
 301â†’    if(journalResult.error){
 302â†’        console.error('error while fetching data from notification table:', journalResult.error);
 303â†’        return res.status(500).json({error: 'error fetching data from notification table'});
 304â†’    }
 305â†’    if(opinionResult.error){
 306â†’        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 307â†’        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 308â†’    }
 309â†’
 310â†’    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 311â†’    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 312â†’
 313â†’    // Merge and sort by created_at descending
 314â†’    const merged = [...journalNotifs, ...opinionNotifs]
 315â†’        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 316â†’
 317â†’    // Likes/bookmarks lookup only for journal notifications
 318â†’    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 319â†’
 320â†’    let hasLikedResult = [];
 321â†’    let hasBookMarkedResult = [];
 322â†’    if(journalIds.length > 0){
 323â†’        const [hasLiked, hasBookMarked] = await Promise.all([
 324â†’            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 325â†’            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 326â†’        ]);
 327â†’
 328â†’        if(hasLiked.error || hasBookMarked.error){
 329â†’            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 330â†’        }
 331â†’        hasLikedResult = hasLiked.data || [];
 332â†’        hasBookMarkedResult = hasBookMarked.data || [];
 333â†’    }
 334â†’
 335â†’    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 336â†’    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 337â†’
 338â†’    const formatted = merged.map((notif) => ({
 339â†’        ...notif,
 340â†’        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 341â†’        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 342â†’    }))
 343â†’
 344â†’    const hasMore = formatted.length > parseInt(limit);
 345â†’    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
 346â†’
 347â†’    return res.status(200).json(
 348â†’        {
 349â†’            hasMore: hasMore,
 350â†’            data: slicedData,
 351â†’        }
 352â†’    )
 353â†’
 354â†’})
