19â†’const apiRequest = async (input, init = {}) => {
20â†’    const method = (init.method || "GET").toUpperCase();
21â†’    const timeoutMs = init.timeoutMs ?? (method === "GET" ? DEFAULT_TIMEOUT_MS : 0);
22â†’    const retries = method === "GET" ? (init.retries ?? DEFAULT_GET_RETRIES) : 0;
23â†’    const { timeoutMs: _, retries: __, signal: callerSignal, ...requestInit } = init;
24â†’
25â†’    for (let attempt = 0; attempt <= retries; attempt++) {
26â†’        const controller = new AbortController();
27â†’        let timedOut = false;
28â†’        let timeoutId = null;
29â†’
30â†’        const forwardAbort = () => controller.abort();
31â†’        if (callerSignal) {
32â†’            if (callerSignal.aborted) {
33â†’                controller.abort();
34â†’            } else {
35â†’                callerSignal.addEventListener("abort", forwardAbort, { once: true });
36â†’            }
37â†’        }
38â†’
39â†’        if (timeoutMs > 0) {
40â†’            timeoutId = setTimeout(() => {
41â†’                timedOut = true;
42â†’                controller.abort();
43â†’            }, timeoutMs);
44â†’        }
45â†’
46â†’        try {
47â†’            const response = await fetch(input, { ...requestInit, signal: controller.signal });
48â†’
49â†’            if (attempt < retries && shouldRetryStatus(response.status)) {
50â†’                await wait(getBackoffDelay(attempt));
51â†’                continue;
52â†’            }
53â†’
54â†’            return response;
55â†’        } catch (error) {
56â†’            if (timedOut) {
57â†’                throw new Error("Request timed out");
58â†’            }
59â†’
60â†’            if (attempt < retries && isRetryableNetworkError(error)) {
61â†’                await wait(getBackoffDelay(attempt));
62â†’                continue;
63â†’            }
64â†’
65â†’            throw error;
66â†’        } finally {
67â†’            if (timeoutId) {
68â†’                clearTimeout(timeoutId);
69â†’            }
70â†’            if (callerSignal) {
71â†’                callerSignal.removeEventListener("abort", forwardAbort);
72â†’            }
73â†’        }
74â†’    }
75â†’
76â†’    throw new Error("Request failed");
77â†’};
