  8â†’export default class ImageNode extends DecoratorNode {
  9â†’  static getType() {
 10â†’    return "image";
 11â†’  }
 12â†’
 13â†’  static clone(node) {
 14â†’    return new ImageNode(
 15â†’      node.__src,
 16â†’      node.__width,
 17â†’      node.__height,
 18â†’      node.__loading,
 19â†’      node.__rotation,
 20â†’      node.__key,
 21â†’    );
 22â†’  }
 23â†’
 24â†’  constructor(src, width = 400, height = 300, loading = false, rotation = 0, key) {
 25â†’    super(key);
 26â†’    this.__src = src;
 27â†’    this.__width = width;
 28â†’    this.__height = height;
 29â†’    this.__loading = loading;
 30â†’    this.__rotation = rotation;
 31â†’  }
 32â†’
 33â†’  createDOM() {
 34â†’    const div = document.createElement("div");
 35â†’    div.className = 'image-container'
 36â†’    return div;
 37â†’  }
 38â†’
 39â†’  updateDOM() {
 40â†’    return false;
 41â†’  }
 42â†’
 43â†’  exportJSON() {
 44â†’    return {
 45â†’      type: "image",
 46â†’      version: 1,
 47â†’      src: this.__src,
 48â†’      width: this.__width,
 49â†’      height: this.__height,
 50â†’      rotation: this.__rotation,
 51â†’    };
 52â†’  }
 53â†’
 54â†’  static importJSON(serializedNode) {
 55â†’    const { src, width, height, rotation } = serializedNode;
 56â†’    return $createImageNode(src, width, height, false, rotation);
 57â†’  }
 58â†’
 59â†’  // update dimensions when user resizes
 60â†’  setWidthAndHeight(width, height) {
 61â†’    const writable = this.getWritable();
 62â†’    writable.__width = width;
 63â†’    writable.__height = height;
 64â†’  }
 65â†’
 66â†’  setRotation(rotation) {
 67â†’    const writable = this.getWritable();
 68â†’    writable.__rotation = rotation;
 69â†’  }
 70â†’
 71â†’  setSrcAndLoading(src, loading) {
 72â†’    const writable = this.getWritable();
 73â†’    writable.__src = src;
 74â†’    writable.__loading = loading;
 75â†’  }
 76â†’
 77â†’  getWidth() {
 78â†’    return this.__width;
 79â†’  }
 80â†’
 81â†’  getHeight() {
 82â†’    return this.__height;
 83â†’  }
 84â†’
 85â†’  decorate(editor) {
 86â†’    const src = this.__src;
 87â†’    const nodeKey = this.getKey();
 88â†’    const width = this.__width;
 89â†’    const height = this.__height;
 90â†’    const loading = this.__loading;
 91â†’    const rotation = this.__rotation;
 92â†’    const isEditable = editor.isEditable();
 93â†’    return <ResizableImageComponent src={src} nodeKey={nodeKey} width={width} height={height} loading={loading} rotation={rotation} isEditable={isEditable}/>;
 94â†’  }
 95â†’}
 96â†’
 97â†’//helper function to create ImageNode
 98â†’export function $createImageNode(src, width = 400, height = 300, loading = false, rotation = 0) {
 99â†’  return new ImageNode(src, width, height, loading, rotation);
100â†’}
