 1â†’const ParseContent = (contentString) => {
 2â†’    if(typeof contentString !== 'string' || !contentString.trim()){
 3â†’        return {
 4â†’            text: [],
 5â†’            slicedText: '',
 6â†’            images: [],
 7â†’            firstImage: null,
 8â†’            wholeText: '',
 9â†’        };
10â†’    }
11â†’    //sample json data to be passed here..
12â†’
13â†’    // {'root': {
14â†’    //     'children': [
15â†’    //         {
16â†’    //             type: 'paragraph', 
17â†’    //             "children": [
18â†’    //                 {
19â†’    //                     'type': 'text',
20â†’    //                     'text': 'some text'
21â†’    //                 },
22â†’    //                 {
23â†’    //                     'type': 'image',
24â†’    //                     'src': "https://hufaxmqdofaycnhdzrxf.supabase.co/...webp",
25â†’    //                     'width': 500,
26â†’    //                     'height': 500
27â†’    //                 }
28â†’    //             ]
29â†’    //         },
30â†’    //     ]
31â†’    // }}
32â†’
33â†’
34â†’    try {
35â†’        const content = JSON.parse(contentString);
36â†’        const root = content.root;
37â†’        const children = root?.children || [];
38â†’        
39â†’        // console.log(children)
40â†’        const parsedData = {
41â†’            text: [],
42â†’            slicedText: [],
43â†’            images: [],
44â†’            firstImage: null,
45â†’            wholeText: null,
46â†’        };
47â†’        const extractFromNodes = (nodes) =>{
48â†’            nodes.forEach((node) => {
49â†’                if(node.type === 'paragraph' || node.type === 'heading'){
50â†’                    //extract text
51â†’                    const textNodes = node.children?.filter((child) => child.type === "text") || [];
52â†’                    const paragraphText = textNodes.map((child) => child.text).join(" "); //join all the array of text into one text form
53â†’
54â†’                    if(paragraphText.trim()) parsedData.text.push(paragraphText);
55â†’
56â†’                    const imageNodes = node.children?.filter((child) => child.type === 'image') || [];
57â†’
58â†’                    imageNodes.forEach((img) => {
59â†’                        const imageData = {src: img.src, width: img.width, height: img.height};
60â†’                        parsedData.images.push(imageData)
61â†’                        if(!parsedData.firstImage) parsedData.firstImage = imageData; //check if firstImage has no image
62â†’                    })
63â†’                }
64â†’
65â†’                if (node.type === "image") {
66â†’                    const imageData = { src: node.src, width: node.width, height: node.height };
67â†’                    parsedData.images.push(imageData);
68â†’                    if (!parsedData.firstImage) parsedData.firstImage = imageData;
69â†’                 }
70â†’
71â†’                if(node.children) extractFromNodes(node.children);
72â†’            });
73â†’        }
74â†’
75â†’        extractFromNodes(children);
76â†’
77â†’        const combinedText = parsedData.text.join(' ').trim();
78â†’        parsedData.wholeText = combinedText;
79â†’        parsedData.slicedText = combinedText.length > 215 ? `${combinedText.substring(0, 215)}...` : combinedText;
80â†’        
81â†’        return parsedData; //return the parsedData
82â†’        } catch (error) {
83â†’            console.error('Error parsing content:', error);
84â†’            return {
85â†’                text: [],
86â†’                slicedText: '',
87â†’                images: [],
88â†’                firstImage: null,
89â†’                wholeText: '',
90â†’            };
91â†’        }
92â†’}
93â†’export default ParseContent;
