 1â†’import { useEffect } from 'react';
 2â†’import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
 3â†’import { $createParagraphNode, $getRoot, $getSelection, $isRangeSelection, COMMAND_PRIORITY_EDITOR } from 'lexical';
 4â†’import { $createImageNode, INSERT_IMAGE_COMMAND } from '../ImageNode';
 5â†’import { $createHeadingNode } from '@lexical/rich-text';
 6â†’
 7â†’export default function ImagePlugin({addUploadedImagePath}) {
 8â†’  const [editor] = useLexicalComposerContext();
 9â†’
10â†’  useEffect(() => {
11â†’    return editor.registerCommand(
12â†’      INSERT_IMAGE_COMMAND,
13â†’      (payload) => {
14â†’        const { src, width, height, loading = false} = payload;
15â†’
16â†’        // only track uploaded paths for non-loading (already uploaded) images
17â†’        if (!loading) {
18â†’          const filePath = src.split('/journal-images/').pop();
19â†’          if(filePath){
20â†’            addUploadedImagePath(filePath)
21â†’          } else {
22â†’            console.warn('Could not extract filePath from src:', src);
23â†’          }
24â†’        }
25â†’
26â†’        const imageNode = $createImageNode(src, width, height, loading);
27â†’        const paragraphNode = $createParagraphNode();
28â†’        const selection = $getSelection();
29â†’        
30â†’        if($isRangeSelection(selection)){
31â†’           selection.insertNodes([imageNode]);
32â†’        }else {
33â†’          const root = $getRoot();
34â†’          root.append(imageNode)
35â†’          root.append(paragraphNode)
36â†’        }
37â†’        
38â†’       
39â†’
40â†’        return true;
41â†’      },
42â†’      COMMAND_PRIORITY_EDITOR
43â†’    );
44â†’  }, [editor]);
45â†’
46â†’  return null;
47â†’}

